CREATE VIEW `ads_center_book_list_view` (`id`, `PlanCode`, `name`, `FirstType`, `SecondType`, `ReceptPage`, `title`, `ShowRule`, `ExposureRule`) AS SELECT `ods`.`a`.`id`, CASE WHEN ((`ods`.`a`.`PlanCode` IS NULL) OR (`ods`.`a`.`PlanCode` = '')) THEN '-' ELSE `ods`.`a`.`PlanCode` END AS `PlanCode`, `ods`.`a`.`name`, CASE WHEN (`ods`.`a`.`FirstType` = 1) THEN '推书_通用' WHEN (`ods`.`a`.`FirstType` = 2) THEN '推书_限时整本免费' WHEN (`ods`.`a`.`FirstType` = 3) THEN '推书_限时章节免费' WHEN (`ods`.`a`.`FirstType` = 4) THEN '专题榜单' WHEN (`ods`.`a`.`FirstType` = 5) THEN '分类标签榜单' WHEN (`ods`.`a`.`FirstType` = 6) THEN '一口价榜单' WHEN (`ods`.`a`.`FirstType` = 7) THEN '书籍介绍' WHEN (`ods`.`a`.`FirstType` = 8) THEN '评论区' WHEN (`ods`.`a`.`FirstType` = 9) THEN '粉丝榜' WHEN (`ods`.`a`.`FirstType` = 10) THEN '作者作品' WHEN (`ods`.`a`.`FirstType` = 11) THEN '首章预览' WHEN (`ods`.`a`.`FirstType` = 12) THEN '推书-定向推送（仅简体）' WHEN (`ods`.`a`.`FirstType` = 13) THEN '折扣榜单' WHEN (`ods`.`a`.`FirstType` = 14) THEN '特殊_排行榜' WHEN (`ods`.`a`.`FirstType` = 15) THEN '特殊_金刚区' WHEN (`ods`.`a`.`FirstType` = 16) THEN '推书_限时整本免费(AD)' WHEN (`ods`.`a`.`FirstType` = 17) THEN '推书_限时章节免费(AD)' WHEN (`ods`.`a`.`FirstType` = 18) THEN '推书_VIP' WHEN (`ods`.`a`.`FirstType` = 19) THEN '最近在看VIP作品' WHEN (`ods`.`a`.`FirstType` = 20) THEN '推书_有声书' ELSE '' END AS `FirstType`, `ods`.`a`.`SecondType`, CASE WHEN (`ods`.`a`.`ReceptPage` = 1) THEN '详情页（默认）' WHEN (`ods`.`a`.`ReceptPage` = 3) THEN '阅读页（首章含简介）' WHEN (`ods`.`a`.`ReceptPage` = 4) THEN '详情页（简化版）' ELSE '-' END AS `ReceptPage`, concat(`ods`.`a`.`BillId`, '_', `ods`.`b`.`Name`) AS `title`, CASE WHEN (`ods`.`a`.`ShowRule` = 1) THEN '随机排序' WHEN (`ods`.`a`.`ShowRule` = 2) THEN '权重排序' WHEN (`ods`.`a`.`ShowRule` = 3) THEN '定时轮播' ELSE '-' END AS `ShowRule`, CASE WHEN (`ods`.`a`.`ExposureRule` = 1) THEN '无限制' WHEN (`ods`.`a`.`ExposureRule` = 2) THEN '单用户曝光N次后，当天不展示；服务器西五区天' WHEN (`ods`.`a`.`ExposureRule` = 3) THEN '单用户点击N次后，当天不展示；服务器西五区天' WHEN (`ods`.`a`.`ExposureRule` = 4) THEN '单用户点击N次后，活动期间不展示' WHEN (`ods`.`a`.`ExposureRule` = 5) THEN '所有用户累计点击N次后，活动期间不展示' WHEN (`ods`.`a`.`ExposureRule` = 6) THEN '单用户曝光N次后，活动期间不展示' WHEN (`ods`.`a`.`ExposureRule` = 7) THEN '所有用户累计点击N次后，当天不展示；服务器西五区天' ELSE '-' END AS `ExposureRule`
FROM `ods`.`ods_tidb_readernovel_tidb_tag_center_book_list` AS `a` LEFT OUTER JOIN `ods`.`ods_tidb_readernovel_tidb_tag_center_book_bill` AS `b` ON `ods`.`a`.`BillId` = `ods`.`b`.`id`;